style.onloaded:
load_pit_hs_inf(*name); 
						capture = (edit_calouttr? true : false); 
						if(callout_transformer.auto_show, popup(); );
						descr = name + '_txt';

style.popup:
 if(callout_transformer.auto_show,
						getlooktodistance(cur_angle, ath, atv);    
						if(cur_angle LE (callout_transformer.visibility_area * view.fov),  
							if(!openhs AND !anime, open_hs_fr(*name)); 
							,
							if(openhs AND !anime, close_hs_fr(*name));	 
						);	 
						delayedcall(0.01, popup()); 
					);

krpano.action:
if(args[1]){

	// получаем все элементы с классом "pulse"
	 var elements = document.getElementsByClassName("pulse"); 

	// установить новый цвет фона во всех элементах класса "pulse"
	 for (var i = 0; i < elements.length; i++) { 
		//elements[i].style.backgroundColor = '#' + args[1];
	} 

	// Получаем стиль переменной CSS
	var style = getComputedStyle(document.documentElement);

	// Меняем значение переменной CSS - круги
	if( args[2]  ==  'border_lr') {
	document.documentElement.style.setProperty('--krugi-bg-color',  '#' + args[1] ); 
	}
	//Изменение цвета точки css анимации  
	if( args[2]  ==  'fill_lr') {
		document.documentElement.style.setProperty('--pit-bg-color',  '#' + args[1] ); 
	} 

	//console.log(elements.background )
}


copy(hs, hotspot[*namhs]);

lin1 = namhs + '_l1';
lin2 = namhs + '_l2';
text = namhs + '_txt';
pit = namhs + '_pit';


addlayer(*lin1, lr);
lr.loadstyle(line_1_inf); 
lr.parent = 'hotspot[' + namhs + ']';
lr.width = hs.l_1;
lr.height =hs.l_thickness;
lr.rotate = hs.rotate_1;
lr.bgcolor =hs.l_color; 


addlayer(*lin2, lr);
lr.loadstyle(line_2_inf); 
lr.parent = lin1 ;
lr.width = hs.l_2;
lr.height =hs.l_thickness;
lr.rotate = hs.rotate_2;
lr.bgcolor =hs.l_color;


addlayer(*text, lr);
lr.loadstyle(text_inf); 
lr.parent = lin2 ;
lr.rotate = hs.rotate_3; 
lr.html = hs.title;
lr.parenths = namhs;
lr.ox = hs.tox;
lr.oy = hs.toy;
lr.bg = hs.t_bg;
lr.bgcolor = hs.t_bgcolor;
lr.bgalpha = hs.t_bgalpha;
lr.bgroundedge = hs.t_bgroundedge;
lr.bgborder = hs.t_bgborder;   
lr.bgshadow = hs.t_bgshadow;
lr.css = hs.css;  		
lr.padding = hs.t_padding;  
lr.txtshadow = hs.t_txtshadow;
lr.width = hs.t_width;
lr.height = hs.t_height;
if(edit_calouttr, draghs = true; hoverTabl = false;  lr.editable= edit_calouttr? true : false;);



addlayer(*pit, lr);
lr.loadstyle(pit_lr_inf);  
lr.parent =  'hotspot[' + namhs + ']';
lr.bgcolor = hs.pit_color;
lr.bgborder = hs.pit_border;
lr.bgroundedge = hs.pit_bgroundedge;
lr.bgshadow = hs.pit_shadow;
lr.width = hs.pit_width;
lr.height = hs.pit_height; 
//if(edit_calouttr, lr.bgcapture = true);

for(set(hsi, 0), hsi LT hotspot.count, inc(hsi),
	hs = hotspot[*hsi];
	if(hs.style == 'pit_hs_inf' ,   
		lin1 = hs.name + '_l1';
		lin2 = hs.name + '_l2';
		text = hs.name + '_txt';  
		hs.openhs = false;  
		layer[*text].alpha = 0; 
		layer[*lin2].width = 0;
		layer[*lin1].width = 0; 
	);
);
callout_transformer.close_all_inf = true;

for(set(hsi, 0), hsi LT hotspot.count, inc(hsi),
	hs = hotspot[*hsi];
	if(hs.style == 'pit_hs_inf' OR  hs.style == 'edit_pit_hs_inf' ,   
		close_hs_fr(*hs.name);  
	);
);
callout_transformer.close_all_inf = true;

hotspot[*namhs].openhs = false; 
lin1 = namhs + '_l1';
lin2 = namhs + '_l2';
text = namhs + '_txt'; 
hs = hotspot[*namhs];  
hs.openhs = false; 
hs.anime = true;

tween(layer[*text].alpha, 0, 0.2); 
tween(layer[*lin2].width, 0, 0.3, default, 
	tween(layer[*lin1].width, 0, 0.3, default,  hs.anime=false);
);

for(set(hsi, 0), hsi LT hotspot.count, inc(hsi),
	hs = hotspot[*hsi];
	if(hs.style == 'pit_hs_inf' OR  hs.style == 'edit_pit_hs_inf' , 
		open_hs_fr(*hs.name); 
		if(callout_transformer.auto_show, callwith(hotspot[*hs.name], popup); );
	);
);
callout_transformer.close_all_inf = false;

lin1 = namhs + '_l1';
lin2 = namhs + '_l2';
text = namhs + '_txt'; 
hs = hotspot[*namhs];  
hs.openhs = true; 
hs.anime = true;

tween(layer[*lin1].width, get(hs.l_1), 0.3, default, 
	tween(layer[*lin2].width, get(hs.l_2), 0.2); 
	tween(layer[*text].alpha, 1, 0.2, default, hs.anime=false); 
);
